import React, { Component } from 'react';
import PropTypes from 'prop-types';
import { withStyles } from '@material-ui/core/styles';
import Fab from '@material-ui/core/Fab';
import AddIcon from '@material-ui/icons/Add';
import Radio from '@material-ui/core/Radio';
import RadioGroup from '@material-ui/core/RadioGroup';
import Select from '@material-ui/core/Select';
import FormControlLabel from '@material-ui/core/FormControlLabel';
import FormControl from '@material-ui/core/FormControl';
import FormLabel from '@material-ui/core/FormLabel';
import MenuItem from '@material-ui/core/MenuItem';
import Input from '@material-ui/core/Input';
import FormHelperText from '@material-ui/core/FormHelperText';
import TextField from '@material-ui/core/TextField';
import Button from '@material-ui/core/Button';
import './App.scss';

const styles = theme => ({
  fab: {
    margin: theme.spacing.unit,
  },
    extendedIcon: {
    marginRight: theme.spacing.unit,
  },
});

class App extends Component {
	constructor(props) {
		super(props);
		this.state = {
			isShowPopup: false,
			so_trung: '',
			ban: 1,
			banh_pho: 'binh-thuong',
			loai_pho: 'pho-bo',
			ghi_chu: '',
			sort_by: 'so_ban',
			edit_id: -1,
			orders: []//global state
		};
		this.togglePopup = this.togglePopup.bind(this);
		this.handleChange = this.handleChange.bind(this);
		this.saveBowl = this.saveBowl.bind(this);
		this.deleteOrder = this.deleteOrder.bind(this);
		this.editOrder = this.editOrder.bind(this);
	}

	resetValuePopup(){
		return{
			so_trung: '',
			ban: 1,
			banh_pho: 'binh-thuong',
			loai_pho: 'pho-bo',
			ghi_chu: '',
			sort_by: 'so_ban',
			edit_id: -1
		}
	}
	
	togglePopup() {
		this.setState({
			isShowPopup: !this.state.isShowPopup
		});

		if(!this.state.isShowPopup){
			this.setState(this.resetValuePopup());
		}
	}
	
  handleChange(e){

    this.setState({
      [e.target.name]: e.target.value
		});

		if(e.target.name === 'sort_by'){
				let orders = JSON.parse(JSON.stringify(this.state.orders));
				switch(e.target.value){
					case 'so_ban':
						orders.sort((a, b) => {
							if(a.ban < b.ban)
								return -1;
							if(a.ban > b.ban)
								return 1;
							return 0;
						});
					break;
					case 'gio_dat':
						orders.sort((a, b) => {
							if(a.ban < b.gio_dat_int)
								return -1;
							if(a.ban > b.gio_dat_int)
								return 1;
							return 0;
						});
					break;
					default:
					break;
				}
				this.setState({orders});
		}
	}

	deleteOrder(e){
		e.preventDefault();
		let orders = JSON.parse(JSON.stringify(this.state.orders));
		let removeIndex = parseInt(e.currentTarget.dataset.id);
		orders.splice(removeIndex, 1);
		this.setState(
			{
				orders
			}
		);
	}

	editOrder(e){
		let 	so_trung =  e.currentTarget.dataset.so_trung,
					ban = e.currentTarget.dataset.ban,
					banh_pho = e.currentTarget.dataset.banh_pho,
					loai_pho =  e.currentTarget.dataset.loai_pho,
					ghi_chu =  e.currentTarget.dataset.ghi_chu,
					edit_id =  e.currentTarget.dataset.id;
		
		this.setState({
			isShowPopup: true,
			so_trung,
			ban,
			banh_pho,
			loai_pho,
			ghi_chu,
			edit_id
		});
	}
	
  saveBowl(e){
    e.preventDefault();
		const orders = JSON.parse(JSON.stringify(this.state.orders));
		let date = new Date();
		let formatDate = `${date.getDate()}/${date.getMonth()+1}/${date.getFullYear()} ${date.getHours()}:${date.getMinutes()}:${date.getSeconds()}`;
		const order = {
			banh_pho: this.state.banh_pho,
			loai_pho: this.state.loai_pho,
			ban: this.state.ban,
			so_trung: this.state.so_trung,
			ghi_chu: this.state.ghi_chu,
			gio_dat: formatDate,
			gio_dat_int: date.getTime()
		};
		
		let {edit_id} = this.state;
		if(edit_id < 0){
			orders.push(order);
		}else{
			orders[edit_id].banh_pho = order.banh_pho;
			orders[edit_id].loai_pho = order.loai_pho;
			orders[edit_id].ban = order.ban;
			orders[edit_id].so_trung = order.so_trung;
			orders[edit_id].ghi_chu = order.ghi_chu;
		}

		if(orders.length > 1){
			orders.sort((a, b) => {
				if(a.ban < b.ban)
					return -1;
				if(a.ban > b.ban)
					return 1;
				return 0;
			});
		}

		this.setState({orders});
	}
	
	render() {
		const { classes } = this.props;
		const { orders } = this.state;
		return (
		<div className="inner-app-wrapper">
			{
				orders.length > 0 &&
				<div className="grid-order">
					<div className="sort-orders">
						<span>Sắp Xếp Theo </span>
						<Select
							value={this.state.sort_by}
							onChange={this.handleChange}
							input={<Input name="sort_by" id="sort-order-by" />}
							>
								<MenuItem value="so_ban">Số bàn</MenuItem>
								<MenuItem value="gio_dat">Giờ Đặt</MenuItem>
						</Select>
					</div>

					<table className="orders-table">
						<thead>
							<tr>
								<th>STT</th>
								<th>Bàn</th>
								<th>Loại Phở</th>
								<th>Bánh Phở</th>
								<th>Chén Trứng</th>
								<th>Ghi Chú</th>
								<th>Giờ Đặt</th>
								<th>Xóa</th>
								<th>Sửa</th>
							</tr>
						</thead>
						<tbody>
						{
							orders.map((order, index) =>( 
								<tr key={index}>
									<td>{index}</td>
									<td>{order.ban}</td>
									<td>{order.loai_pho}</td>
									<td>{order.banh_pho}</td>
									<td>{order.so_trung}</td>
									<td>{order.ghi_chu}</td>
									<td>{order.gio_dat}</td>
									<td>
										<Button variant="contained" type="button" color="primary" className={classes.button} onClick={this.deleteOrder} data-id={index}>
											Xóa
										</Button>
									</td>
									<td>
										<Button variant="contained" type="button" color="primary" className={classes.button} onClick={this.editOrder} 
											data-id={index}
											data-ban={order.ban}
											data-banh_pho={order.banh_pho}
											data-loai_pho={order.loai_pho}
											data-so_trung={order.so_trung}
											data-ghi_chu={order.ghi_chu}>
											Sửa
										</Button>
									</td>
								</tr>
							))
						}
						</tbody>
					</table>
				</div>
			}
			{
			this.state.isShowPopup &&
				<div className="bow-detail-wrapper popup">
					<div className="popup-content">
						<h2 className="popup-title">{this.state.edit_id < 0 ? "Thêm mới" : "Sửa"}</h2>
						<form className={classes.form} noValidate id="new-bowl" onSubmit={this.saveBowl}>
							<FormControl component="fieldset" className={classes.formControl}>
								<FormLabel component="legend">Sô Lượng Bánh Phở</FormLabel>
								<RadioGroup
									aria-label="Gender"
									name="banh_pho"
									className={classes.group}
									value={this.state.banh_pho}
									onChange={this.handleChange}
									>
									<FormControlLabel value="binh-thuong" control={<Radio />} label="Bình Thường" />
									<FormControlLabel value="it-banh" control={<Radio />} label="Ít Bánh" />
									<FormControlLabel value="nhieu-banh" control={<Radio />} label="Nhiều Bánh" />
								</RadioGroup>
							</FormControl>

							<FormControl component="fieldset" className={classes.formControl}>
								<FormLabel component="legend">Loại Phở</FormLabel>
								<RadioGroup
									aria-label="Gender"
									name="loai_pho"
									className={classes.group}
									value={this.state.loai_pho}
									onChange={this.handleChange}
									>
									<FormControlLabel value="pho-bo" control={<Radio />} label="Phở Bò" />
									<FormControlLabel value="pho-ga" control={<Radio />} label="Phở Gà" />
								</RadioGroup>
							</FormControl>

							<FormControl component="fieldset" className={classes.formControl}>
								<FormLabel component="legend">Món ăn kèm</FormLabel>
								<Select
									value={this.state.so_trung}
									onChange={this.handleChange}
									input={<Input name="so_trung" id="mon-an-kem-trung" />}
									>
										<MenuItem value="">
										<em>0</em>
										</MenuItem>
										<MenuItem value={1}>1</MenuItem>
										<MenuItem value={2}>2</MenuItem>
										<MenuItem value={3}>3</MenuItem>
										<MenuItem value={4}>4</MenuItem>
										<MenuItem value={5}>5</MenuItem>
								</Select>
								<FormHelperText>Trứng</FormHelperText>
							</FormControl>

							<FormControl component="fieldset" className={classes.formControl}>
								<FormLabel component="legend">Số bàn</FormLabel>
								<Select
									value={this.state.ban}
									onChange={this.handleChange}
									input={<Input name="ban" id="so-ban" />}
									>
									<MenuItem value="">
									<em>0</em>
									</MenuItem>
									<MenuItem value={1}>1</MenuItem>
									<MenuItem value={2}>2</MenuItem>
									<MenuItem value={3}>3</MenuItem>
									<MenuItem value={4}>4</MenuItem>
									<MenuItem value={5}>5</MenuItem>
								</Select>
								<FormHelperText>Số Bàn</FormHelperText>
							</FormControl>

							<FormControl component="fieldset" className={classes.formControl}>
								<TextField
									id="ghi-chu"
									label="Ghi Chú"
									type="text"
									name="ghi_chu"
									className={classes.textField}
									multiline
									margin="normal"
									onChange={this.handleChange}
								/>
							</FormControl>

							<FormControl component="fieldset" className={classes.formControl}>
								<Button variant="contained" type="submit" color="secondary" className={classes.button}>
									Lưu
								</Button>
							</FormControl>

							<FormControl component="fieldset" className={classes.formControl}>
								<Button variant="contained" type="button" color="primary" className={classes.button} onClick={this.togglePopup}>
									Đóng
								</Button>
							</FormControl>
						</form>
					</div>
				</div>
				}
				<Fab color="secondary" aria-label="Add" className="add-bowl float" onClick={this.togglePopup}>
					<AddIcon />
				</Fab>
			</div>
			)
  }
}


App.propTypes = {
  classes: PropTypes.object.isRequired,
};

export default withStyles(styles)(App);